const body = $json.body ?? {};
const urls = Array.isArray(body.urls) ? body.urls.filter((url) => typeof url === 'string' && url.trim() !== '') : [];

if (!body.productName || urls.length === 0) {
  throw new Error('competitor 流程需要 productName 與至少一個 urls。');
}

return urls.map((url, index) => ({
  json: {
    workflowType: 'competitor',
    productName: body.productName,
    market: body.market ?? 'TW',
    originalUrl: url,
    scrapeIndex: index + 1,
    firecrawlPayload: {
      url,
      formats: ['markdown']
    }
  }
}));

const items = $input.all();
const first = items[0]?.json ?? {};
const sections = items.map((item, index) => {
  const payload = item.json;
  const sourceUrl = payload.originalUrl ?? payload.firecrawlPayload?.url ?? `來源 ${index + 1}`;
  const markdown = payload.data?.markdown ?? payload.markdown ?? payload.content ?? '資料不足';
  return `來源 ${index + 1}
URL: ${sourceUrl}

${markdown}`;
});

const scrapedData = sections.join('

-----

');
const prompt = `你現在是一位頂尖的 Meta 廣告策略顧問與市場分析師。
請根據以下 <scraped_data> 內的競品網頁文字，產出可直接給商務端閱讀的專業分析。

任務要求：
1. 提煉競品核心賣點：總結這幾個競品主打的最大優勢。
2. 找出市場痛點：根據頁面內容，推斷消費者未被滿足的渴望、顧慮或抱怨。
3. 多樣化概念建議：針對我的產品提出 5 個完全不同的廣告切入概念，每個概念都必須包含：概念名稱、目標客群、切入痛點、文案方向。
4. 若資料品質不足，不能只停在「資料不足」；必須額外輸出「建議下一步」，具體告訴使用者如何補件，讓系統下次能拿到可分析資料。

補充產品資訊：
我的產品名稱：${first.productName ?? '未提供'}
目標市場：${first.market ?? '未提供'}

資料不足時的處理規則：
- 若 <scraped_data> 主要是安全驗證頁、登入頁、阻擋頁、空白頁、導轉頁，請明確指出目前擷取內容不足以支持完整判斷。
- 仍然要盡量從可讀內容提煉有限資訊，不能直接停止。
- 必須提供至少 3 條具體補件建議，例如：提供可直接開啟的產品頁、銷售頁、關於頁、FAQ 頁，貼上更多競品網址，補充產品文字介紹，上傳競品頁面截圖，或增加圖片上傳分析功能來解析廣告素材與落地頁畫面。

輸出格式要求：
- 使用繁體中文。
- 請輸出純文字格式，不要使用 Markdown 符號。
- 禁止使用 #、##、###、*、**、\`\`\` 這類符號。
- 以清楚的段落標題呈現，例如：競品核心賣點、市場痛點、廣告概念建議、建議下一步。

防幻覺機制：
- 嚴格僅使用 <scraped_data> 內的資訊進行分析。
- 絕不可捏造未提及的數據、功能、客戶案例或市佔率。
- 若資料不足，只能做有限推測，並清楚標示推測基礎。

<scraped_data>
${scrapedData}
</scraped_data>`;

return [
  {
    json: {
      workflowType: 'competitor',
      prompt,
      scrapedData,
      productName: first.productName ?? '',
      market: first.market ?? ''
    }
  }
];

const body = $('Webhook - Analyze Market').first().json.body ?? {};
const organic = Array.isArray($json.organic) ? $json.organic : [];
const links = organic
  .map((item) => item.link)
  .filter((link) => typeof link === 'string' && link.trim() !== '')
  .slice(0, 3);

if (links.length === 0) {
  throw new Error('Serper 沒有回傳可供 Firecrawl 抓取的連結。');
}

return links.map((url, index) => ({
  json: {
    workflowType: 'concept',
    conceptDesc: body.conceptDesc ?? '',
    market: body.market ?? 'TW',
    searchUrl: url,
    searchIndex: index + 1,
    firecrawlPayload: {
      url,
      formats: ['markdown']
    }
  }
}));

const items = $input.all();
const first = items[0]?.json ?? {};
const sections = items.map((item, index) => {
  const payload = item.json;
  const sourceUrl = payload.searchUrl ?? payload.firecrawlPayload?.url ?? `來源 ${index + 1}`;
  const markdown = payload.data?.markdown ?? payload.markdown ?? payload.content ?? '資料不足';
  return `搜尋來源 ${index + 1}
URL: ${sourceUrl}

${markdown}`;
});

const scrapedData = sections.join('

