const prompt = `你現在是一位具備頂尖商業嗅覺的 SaaS 產品開發顧問。
請根據以下 <scraped_data> 的市場搜尋結果內文，針對我提出的產品概念進行市場驗證與發想。

我的產品概念：${first.conceptDesc ?? '未提供'}
目標市場區域：${first.market ?? '未提供'}

任務要求：
1. 市場現況總結：目前市場上解決類似問題的方案有哪些，競爭狀態如何。
2. 差異化突圍策略：我的概念在哪裡具有有意義的差異化。
3. 廣告概念矩陣：請為我的產品生成 9 個多樣化廣告概念，必須涵蓋冷受眾、溫受眾、熱受眾三個階段，每階段 3 個概念。
4. 若資料品質不足，不能只停在資料不足，必須提出具體補件與下一步建議。

資料不足時的處理規則：
- 若搜尋結果主要是安全驗證頁、無法讀取頁、極少內容頁，請明確指出目前資料不足以支持完整市場判斷。
- 仍要整理目前可讀到的有限資訊，不能直接停止。
- 必須提供至少 3 條具體補件建議，例如：補充更完整的產品概念描述、指定更明確的市場關鍵字、提供同類競品網址、貼上品牌官網與產品頁、上傳市場頁面截圖或廣告素材圖片，或增加圖片上傳分析功能。

輸出格式要求：
- 使用繁體中文。
- 請輸出純文字格式，不要使用 Markdown 符號。
- 禁止使用 #、##、###、*、**、\`\`\` 這類符號。
- 以清楚的段落標題呈現，例如：市場現況總結、差異化突圍策略、廣告概念矩陣、建議下一步。

防幻覺機制：
- 結論必須基於 <scraped_data> 的客觀內容，不得自行想像地區市佔率或不存在的品牌資料。
- 若資料不足，只能做有限推測，並清楚交代推測基礎。

<scraped_data>
${scrapedData}
</scraped_data>`;

return [
  {
    json: {
      workflowType: 'concept',
      prompt,
      scrapedData,
      conceptDesc: first.conceptDesc ?? '',
      market: first.market ?? ''
    }
  }
];

const candidate = $json.candidates?.[0];
const parts = candidate?.content?.parts ?? [];
const markdown = parts.map((part) => part.text).filter(Boolean).join('\n\n');

return [
  {
    json: {
      ok: true,
      type: 'competitor',
      result: markdown || 'Gemini 未回傳內容。',
      raw: $json
    }
  }
];

